import Decimal from 'decimal.js';
import type { Candle } from '../core/types.js';

Decimal.set({ precision: 20, rounding: Decimal.ROUND_HALF_UP });

/** Add two numbers with decimal precision */
export function add(a: number, b: number): number {
  return new Decimal(a).plus(b).toNumber();
}

/** Subtract b from a with decimal precision */
export function sub(a: number, b: number): number {
  return new Decimal(a).minus(b).toNumber();
}

/** Multiply two numbers with decimal precision */
export function mul(a: number, b: number): number {
  return new Decimal(a).times(b).toNumber();
}

/** Divide a by b with decimal precision */
export function div(a: number, b: number): number {
  if (b === 0) return 0;
  return new Decimal(a).dividedBy(b).toNumber();
}

/** Absolute value */
export function abs(a: number): number {
  return new Decimal(a).abs().toNumber();
}

/** Calculate midpoint between two prices */
export function midpoint(a: number, b: number): number {
  return new Decimal(a).plus(b).dividedBy(2).toNumber();
}

/** Calculate percentage change from a to b */
export function percentChange(from: number, to: number): number {
  if (from === 0) return 0;
  return new Decimal(to).minus(from).dividedBy(new Decimal(from).abs()).times(100).toNumber();
}

/** Calculate fibonacci retracement level: high - (high - low) * ratio */
export function fibLevel(high: number, low: number, ratio: number): number {
  const range = new Decimal(high).minus(low);
  return new Decimal(high).minus(range.times(ratio)).toNumber();
}

/** Calculate distance in points between two prices */
export function pointsDistance(a: number, b: number): number {
  return new Decimal(a).minus(b).abs().toNumber();
}

/**
 * Check if two prices are approximately equal within a tolerance.
 * Used for detecting equal highs / equal lows.
 */
export function isApproxEqual(a: number, b: number, tolerance: number): boolean {
  return new Decimal(a).minus(b).abs().lte(tolerance);
}

/** Check if a > b with decimal precision */
export function isGreater(a: number, b: number): boolean {
  return new Decimal(a).greaterThan(b);
}

/** Check if a < b with decimal precision */
export function isLess(a: number, b: number): boolean {
  return new Decimal(a).lessThan(b);
}

/** Check if a >= b with decimal precision */
export function isGte(a: number, b: number): boolean {
  return new Decimal(a).greaterThanOrEqualTo(b);
}

/** Check if a <= b with decimal precision */
export function isLte(a: number, b: number): boolean {
  return new Decimal(a).lessThanOrEqualTo(b);
}

/** Round to a specific number of decimal places */
export function roundTo(value: number, decimals: number): number {
  return new Decimal(value).toDecimalPlaces(decimals).toNumber();
}

/**
 * Calculate Average True Range over a period.
 * TR = max(H-L, |H-prevC|, |L-prevC|)
 */
export function atr(candles: readonly Candle[], period: number): number {
  if (candles.length < 2) return 0;
  const effectivePeriod = Math.min(period, candles.length - 1);
  let sum = new Decimal(0);

  for (let i = candles.length - effectivePeriod; i < candles.length; i++) {
    const candle = candles[i]!;
    const prev = candles[i - 1]!;
    const hl = new Decimal(candle.high).minus(candle.low);
    const hpc = new Decimal(candle.high).minus(prev.close).abs();
    const lpc = new Decimal(candle.low).minus(prev.close).abs();
    sum = sum.plus(Decimal.max(hl, hpc, lpc));
  }

  return sum.dividedBy(effectivePeriod).toNumber();
}

/** Find the minimum value from an array of numbers */
export function min(...values: number[]): number {
  return Decimal.min(...values.map(v => new Decimal(v))).toNumber();
}

/** Find the maximum value from an array of numbers */
export function max(...values: number[]): number {
  return Decimal.max(...values.map(v => new Decimal(v))).toNumber();
}

